head.b:skin:
/* ===== Theme Designer Variables ===== */
/*
<Group description="Brand Colors" selector="body">
  <Variable name="primary.color" description="Primary Color" type="color" default="#2563EB" value="#2563EB"/>
  <Variable name="secondary.color" description="Secondary Color" type="color" default="#1E293B" value="#1E293B"/>
  <Variable name="accent.color" description="Accent Color" type="color" default="#06B6D4" value="#06B6D4"/>
  <Variable name="body.bg" description="Body Background" type="color" default="#F8FAFC" value="#F8FAFC"/>
</Group>
<Group description="Typography" selector="body">
  <Variable name="body.font" description="Body Font" type="font" default="normal normal 15px Inter, sans-serif" value="normal normal 15px Inter, sans-serif"/>
  <Variable name="heading.font" description="Heading Font" type="font" default="normal bold 700 28px &#39;Plus Jakarta Sans&#39;, sans-serif" value="normal bold 700 28px &#39;Plus Jakarta Sans&#39;, sans-serif"/>
</Group>
*/

:root{
  --primary:#2563EB;
  --primary-d:#1D4ED8;
  --secondary:#1E293B;
  --accent:#06B6D4;
  --bg:#F8FAFC;
  --card:#FFFFFF;
  --text:#0F172A;
  --muted:#64748B;
  --border:#E2E8F0;
  --glass:rgba(255,255,255,.7);
  --shadow:0 10px 30px rgba(15,23,42,.08);
  --shadow-lg:0 20px 60px rgba(37,99,235,.15);
  --radius:16px;
  --radius-sm:10px;
  --maxw:1240px;
  --grad:linear-gradient(135deg,#2563EB 0%,#06B6D4 100%);
}
[data-theme="dark"]{
  --bg:#0B1220;
  --card:#111A2E;
  --text:#E2E8F0;
  --muted:#94A3B8;
  --border:#1E293B;
  --glass:rgba(17,26,46,.7);
  --shadow:0 10px 30px rgba(0,0,0,.4);
  --shadow-lg:0 20px 60px rgba(0,0,0,.5);
}

*{box-sizing:border-box;margin:0;padding:0}
html{scroll-behavior:smooth;-webkit-text-size-adjust:100%}
body{
  font-family:Inter,'Segoe UI',system-ui,-apple-system,sans-serif;
  background:var(--bg);
  color:var(--text);
  line-height:1.65;
  font-size:15px;
  overflow-x:hidden;
  transition:background .3s ease,color .3s ease;
}
h1,h2,h3,h4,h5{font-family:'Plus Jakarta Sans',Inter,sans-serif;font-weight:800;line-height:1.2;letter-spacing:-.02em}
a{color:var(--primary);text-decoration:none;transition:.2s}
a:hover{color:var(--accent)}
img{max-width:100%;height:auto;display:block}
ul,ol{padding-left:1.2rem}

.container{max-width:var(--maxw);margin:0 auto;padding:0 20px}
.sr-only{position:absolute;width:1px;height:1px;padding:0;margin:-1px;overflow:hidden;clip:rect(0,0,0,0);border:0}

/* Buttons */
.btn{display:inline-flex;align-items:center;gap:8px;font-weight:600;font-size:15px;padding:13px 26px;border-radius:var(--radius-sm);border:none;cursor:pointer;transition:transform .15s,box-shadow .2s;font-family:inherit;white-space:nowrap}
.btn-primary{background:var(--grad);color:#fff;box-shadow:0 8px 20px rgba(37,99,235,.35)}
.btn-primary:hover{color:#fff;transform:translateY(-2px);box-shadow:0 12px 28px rgba(37,99,235,.45)}
.btn-ghost{background:var(--card);color:var(--text);border:1px solid var(--border)}
.btn-ghost:hover{color:var(--primary);border-color:var(--primary)}
.btn-block{width:100%;justify-content:center}

/* Glass card */
.glass{background:var(--glass);backdrop-filter:blur(18px) saturate(140%);-webkit-backdrop-filter:blur(18px) saturate(140%);border:1px solid rgba(255,255,255,.4);border-radius:var(--radius);box-shadow:var(--shadow)}
[data-theme="dark"] .glass{border-color:rgba(255,255,255,.08)}

.card{background:var(--card);border:1px solid var(--border);border-radius:var(--radius);box-shadow:var(--shadow)}

/* ===== HEADER ===== */
.site-header{position:sticky;top:0;z-index:900;background:var(--glass);backdrop-filter:blur(16px);border-bottom:1px solid var(--border)}
.nav{display:flex;align-items:center;justify-content:space-between;padding:14px 20px;max-width:var(--maxw);margin:0 auto;gap:16px}
.brand{display:flex;align-items:center;gap:10px;font-family:'Plus Jakarta Sans',sans-serif;font-weight:800;font-size:22px;color:var(--secondary)}
.brand:hover{color:var(--secondary)}
[data-theme="dark"] .brand{color:#fff}
[data-theme="dark"] .brand:hover{color:#fff}
.brand .logo{width:38px;height:38px;border-radius:10px;background:var(--grad);display:grid;place-items:center;color:#fff;font-size:18px;box-shadow:0 6px 16px rgba(37,99,235,.4)}
.brand span{color:var(--primary)}
[data-theme="dark"] .brand span{color:#60A5FA}
.nav-menu{display:flex;align-items:center;gap:6px;list-style:none;padding:0;margin:0}
.nav-menu a{display:inline-block;padding:9px 14px;border-radius:10px;color:var(--text);font-weight:500;font-size:15px}
.nav-menu a:hover{background:rgba(37,99,235,.08);color:var(--primary)}
.nav-actions{display:flex;align-items:center;gap:8px}
.theme-toggle,.menu-toggle{background:transparent;border:1px solid var(--border);width:42px;height:42px;border-radius:11px;cursor:pointer;display:grid;place-items:center;color:var(--text);font-size:18px}
.theme-toggle:hover,.menu-toggle:hover{border-color:var(--primary);color:var(--primary)}
.menu-toggle{display:none}
body.nav-open{overflow:hidden}
body.nav-open .nav-mobile{transform:translateX(0)}
.nav-mobile{position:fixed;inset:64px 0 0 0;background:var(--bg);z-index:950;transform:translateX(100%);transition:transform .3s ease;padding:30px;display:flex;flex-direction:column;gap:6px}
.nav-mobile a{padding:16px;font-size:18px;font-weight:600;border-bottom:1px solid var(--border);color:var(--text)}
.nav-mobile a:hover{color:var(--primary)}
.nav-mobile .btn{margin-top:16px}

/* ===== HERO ===== */
.hero{position:relative;padding:80px 0 70px;overflow:hidden}
.hero::before{content:"";position:absolute;top:-150px;right:-150px;width:520px;height:520px;background:radial-gradient(circle,rgba(37,99,235,.18),transparent 70%);border-radius:50%;z-index:-1}
.hero::after{content:"";position:absolute;bottom:-200px;left:-100px;width:460px;height:460px;background:radial-gradient(circle,rgba(6,182,212,.15),transparent 70%);border-radius:50%;z-index:-1}
.hero-grid{display:grid;grid-template-columns:1.1fr .9fr;gap:50px;align-items:center}
.hero-eyebrow{display:inline-flex;align-items:center;gap:8px;background:rgba(37,99,235,.08);color:var(--primary);padding:7px 14px;border-radius:30px;font-weight:600;font-size:13px;margin-bottom:22px}
.hero h1{font-size:clamp(34px,5vw,56px);line-height:1.08;margin-bottom:20px}
.hero h1 .grad{background:var(--grad);-webkit-background-clip:text;background-clip:text;-webkit-text-fill-color:transparent}
.hero p.lead{font-size:19px;color:var(--muted);max-width:540px;margin-bottom:30px}
.hero-cta{display:flex;gap:14px;flex-wrap:wrap;margin-bottom:34px}
.hero-stats{display:flex;gap:34px;flex-wrap:wrap}
.hero-stats .stat b{display:block;font-size:28px;font-family:'Plus Jakarta Sans',sans-serif;color:var(--primary)}
.hero-stats .stat span{color:var(--muted);font-size:13px}

.hero-card{background:var(--card);border:1px solid var(--border);border-radius:22px;box-shadow:var(--shadow-lg);padding:26px;position:relative}
.hero-card .mini-invoice{background:linear-gradient(135deg,#F8FAFC,#EFF6FF);border:1px solid var(--border);border-radius:14px;padding:20px}
[data-theme="dark"] .hero-card .mini-invoice{background:linear-gradient(135deg,#0B1220,#111A2E)}
.hero-card .mi-top{display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:18px}
.hero-card .mi-title{font-weight:800;font-size:18px}
.hero-card .mi-badge{background:var(--grad);color:#fff;padding:5px 12px;border-radius:20px;font-size:12px;font-weight:600}
.hero-card .mi-row{display:flex;justify-content:space-between;padding:9px 0;border-bottom:1px dashed var(--border);font-size:14px}
.hero-card .mi-row.total{border-bottom:none;font-weight:700;font-size:17px;padding-top:14px}
.hero-card .mi-row.total .amt{color:var(--primary)}
.hero-card .mi-bar{height:6px;background:var(--border);border-radius:6px;margin-top:8px;overflow:hidden}
.hero-card .mi-bar i{display:block;height:100%;width:78%;background:var(--grad)}

/* ===== SECTIONS ===== */
.section{padding:70px 0}
.section-head{text-align:center;max-width:680px;margin:0 auto 50px}
.section-head .eyebrow{color:var(--accent);font-weight:700;letter-spacing:.1em;text-transform:uppercase;font-size:13px}
.section-head h2{font-size:clamp(28px,4vw,40px);margin:12px 0}
.section-head p{color:var(--muted);font-size:17px}

.grid{display:grid;gap:24px}
.grid-3{grid-template-columns:repeat(3,1fr)}
.grid-4{grid-template-columns:repeat(4,1fr)}
.grid-2{grid-template-columns:repeat(2,1fr)}

.feature{padding:30px;border-radius:var(--radius);background:var(--card);border:1px solid var(--border);transition:transform .2s,box-shadow .2s}
.feature:hover{transform:translateY(-6px);box-shadow:var(--shadow-lg);border-color:var(--primary)}
.feature .ico{width:56px;height:56px;border-radius:14px;background:rgba(37,99,235,.1);color:var(--primary);display:grid;place-items:center;font-size:24px;margin-bottom:18px}
.feature h3{font-size:19px;margin-bottom:10px}
.feature p{color:var(--muted);font-size:15px}

.tool{display:flex;gap:20px;padding:26px;border-radius:var(--radius);background:var(--card);border:1px solid var(--border);align-items:center;transition:.2s}
.tool:hover{transform:translateY(-4px);box-shadow:var(--shadow-lg)}
.tool .tico{width:62px;height:62px;border-radius:14px;background:var(--grad);color:#fff;display:grid;place-items:center;font-size:28px;flex-shrink:0}
.tool h3{font-size:18px;margin-bottom:4px}
.tool p{color:var(--muted);font-size:14px;margin-bottom:10px}
.tool a.arrow{font-weight:600;font-size:14px}

/* Steps */
.steps{counter-reset:step}
.step{display:flex;gap:22px;padding:24px 0;border-bottom:1px solid var(--border);position:relative}
.step:last-child{border-bottom:none}
.step .n{width:52px;height:52px;border-radius:14px;background:var(--card);border:2px solid var(--primary);color:var(--primary);display:grid;place-items:center;font-weight:800;font-size:20px;font-family:'Plus Jakarta Sans';flex-shrink:0}
.step h3{font-size:18px;margin-bottom:6px}
.step p{color:var(--muted)}

/* FAQ */
.faq-item{background:var(--card);border:1px solid var(--border);border-radius:var(--radius-sm);margin-bottom:14px;overflow:hidden}
.faq-q{width:100%;text-align:left;background:none;border:none;padding:20px 24px;font-size:17px;font-weight:700;font-family:inherit;color:var(--text);cursor:pointer;display:flex;justify-content:space-between;align-items:center;gap:14px}
.faq-q .pm{font-size:24px;color:var(--primary);transition:transform .2s}
.faq-item.open .pm{transform:rotate(45deg)}
.faq-a{max-height:0;overflow:hidden;transition:max-height .3s ease;color:var(--muted)}
.faq-a div{padding:0 24px 22px}

/* CTA */
.cta{position:relative;background:var(--grad);border-radius:26px;padding:60px 40px;text-align:center;color:#fff;overflow:hidden}
.cta::before{content:"";position:absolute;inset:0;background:radial-gradient(circle at 20% 30%,rgba(255,255,255,.2),transparent 40%)}
.cta h2{font-size:clamp(28px,4vw,40px);margin-bottom:14px;color:#fff;position:relative}
.cta p{font-size:18px;opacity:.92;max-width:600px;margin:0 auto 30px;position:relative}
.cta .btn{background:#fff;color:var(--primary);position:relative}
.cta .btn:hover{transform:translateY(-2px);color:var(--primary-d)}

/* ===== TOOL PAGES ===== */
.tool-page{padding:50px 0 80px}
.tool-layout{display:grid;grid-template-columns:1fr 1fr;gap:30px;align-items:start}
.tool-form{padding:28px}
.tool-form h2{font-size:24px;margin-bottom:6px}
.tool-form .sub{color:var(--muted);font-size:14px;margin-bottom:24px}
.field{margin-bottom:16px}
.field label{display:block;font-weight:600;font-size:13px;margin-bottom:6px;color:var(--text)}
.field input,.field select,.field textarea{width:100%;padding:12px 14px;border:1.5px solid var(--border);border-radius:10px;background:var(--bg);color:var(--text);font-family:inherit;font-size:15px;transition:.15s}
[data-theme="dark"] .field input,[data-theme="dark"] .field select,[data-theme="dark"] .field textarea{background:#0B1220}
.field input:focus,.field select:focus,.field textarea:focus{outline:none;border-color:var(--primary);box-shadow:0 0 0 3px rgba(37,99,235,.15)}
.field-row{display:grid;grid-template-columns:1fr 1fr;gap:14px}
.items-table{width:100%;border-collapse:collapse;margin:10px 0 16px}
.items-table th{text-align:left;font-size:12px;color:var(--muted);text-transform:uppercase;letter-spacing:.05em;padding:8px 6px;font-weight:700}
.items-table td{padding:6px}
.items-table input{width:100%;padding:9px 10px;border:1.5px solid var(--border);border-radius:8px;background:var(--bg);color:var(--text);font-size:14px;font-family:inherit}
[data-theme="dark"] .items-table input{background:#0B1220}
.items-table input:focus{outline:none;border-color:var(--primary)}
.items-table .col-qty,.items-table .col-price{max-width:90px}
.items-table .del-row{width:34px;background:transparent;border:none;color:#EF4444;cursor:pointer;font-size:18px;border-radius:8px}
.add-item{background:rgba(37,99,235,.08);color:var(--primary);border:1.5px dashed var(--primary);padding:11px;border-radius:10px;width:100%;cursor:pointer;font-weight:600;font-size:14px;margin-bottom:18px;font-family:inherit}
.totals{background:rgba(37,99,235,.04);border-radius:12px;padding:18px;margin-top:6px}
.totals .trow{display:flex;justify-content:space-between;padding:7px 0;font-size:15px}
.totals .trow.grand{border-top:2px solid var(--border);margin-top:6px;padding-top:13px;font-size:19px;font-weight:800;font-family:'Plus Jakarta Sans'}
.totals .trow.grand .amt{color:var(--primary)}
.tool-actions{display:flex;gap:10px;flex-wrap:wrap;margin-top:20px}
.tool-actions .btn{flex:1;min-width:140px;justify-content:center}
.note{font-size:12.5px;color:var(--muted);margin-top:14px;display:flex;gap:8px;align-items:flex-start;background:rgba(6,182,212,.08);padding:11px 13px;border-radius:10px;border-left:3px solid var(--accent)}

/* Preview / Document */
.preview-wrap{position:sticky;top:84px}
.preview-toolbar{display:flex;justify-content:space-between;align-items:center;margin-bottom:14px;flex-wrap:wrap;gap:10px}
.preview-toolbar .ttl{font-weight:700;font-size:16px}
.doc{background:#fff;color:#1E293B;border-radius:14px;padding:42px;box-shadow:var(--shadow-lg);min-height:520px;font-family:Inter,sans-serif}
.doc .doc-head{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:3px solid #2563EB;padding-bottom:22px;margin-bottom:26px}
.doc .doc-brand{font-family:'Plus Jakarta Sans';font-weight:800;font-size:26px;color:#1E293B}
.doc .doc-brand span{color:#2563EB}
.doc .doc-type{font-size:32px;font-weight:800;font-family:'Plus Jakarta Sans';color:#2563EB;letter-spacing:-.02em}
.doc .doc-meta{text-align:right;color:#64748B;font-size:13px;line-height:1.7}
.doc .doc-meta b{color:#1E293B}
.doc .parties{display:grid;grid-template-columns:1fr 1fr;gap:20px;margin-bottom:24px}
.doc .party .lbl{font-size:11px;text-transform:uppercase;letter-spacing:.08em;color:#94A3B8;font-weight:700;margin-bottom:4px}
.doc .party .nm{font-weight:700;font-size:16px;color:#1E293B;margin-bottom:3px}
.doc .party .det{font-size:13px;color:#64748B;line-height:1.6;white-space:pre-line}
.doc table.doc-items{width:100%;border-collapse:collapse;margin:14px 0}
.doc table.doc-items th{background:#1E293B;color:#fff;text-align:left;padding:12px 14px;font-size:12px;text-transform:uppercase;letter-spacing:.05em}
.doc table.doc-items th:last-child,.doc table.doc-items td:last-child{text-align:right}
.doc table.doc-items td{padding:12px 14px;border-bottom:1px solid #E2E8F0;font-size:14px}
.doc table.doc-items tr:last-child td{border-bottom:none}
.doc .doc-totals{margin-left:auto;width:280px;margin-top:18px}
.doc .doc-totals .trow{display:flex;justify-content:space-between;padding:7px 0;font-size:14px;color:#64748B}
.doc .doc-totals .trow b{color:#1E293B}
.doc .doc-totals .grand{border-top:2px solid #1E293B;margin-top:6px;padding-top:12px;font-size:20px;font-weight:800;color:#1E293B;font-family:'Plus Jakarta Sans'}
.doc .doc-totals .grand .amt{color:#2563EB}
.doc .doc-foot{margin-top:36px;padding-top:20px;border-top:1px solid #E2E8F0;font-size:12px;color:#94A3B8;text-align:center}
.doc .status-pill{display:inline-block;padding:4px 12px;border-radius:20px;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.05em}
.doc .status-pill.paid{background:#DCFCE7;color:#166534}
.doc .status-pill.unpaid{background:#FEE2E2;color:#991B1B}
.doc .status-pill.partial{background:#FEF3C7;color:#92400E}
.preview-empty{text-align:center;padding:80px 20px;color:var(--muted)}
.preview-empty .em{font-size:54px;margin-bottom:14px}

/* ===== CONTENT / BLOG ===== */
.layout{display:grid;grid-template-columns:1fr 320px;gap:34px;padding:40px 0 70px}
.crumbs{font-size:13px;color:var(--muted);margin-bottom:18px;display:flex;gap:8px;flex-wrap:wrap;align-items:center}
.crumbs a{color:var(--muted)}
.crumbs a:hover{color:var(--primary)}
.crumbs .sep{opacity:.5}
.crumbs .cur{color:var(--text);font-weight:600}

.post-card{background:var(--card);border:1px solid var(--border);border-radius:var(--radius);overflow:hidden;display:flex;flex-direction:column;transition:.2s}
.post-card:hover{transform:translateY(-5px);box-shadow:var(--shadow-lg)}
.post-card .thumb{aspect-ratio:16/9;background:var(--grad);position:relative;overflow:hidden}
.post-card .thumb img{width:100%;height:100%;object-fit:cover}
.post-card .body{padding:22px;flex:1;display:flex;flex-direction:column}
.post-card .cat{display:inline-block;color:var(--accent);font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;margin-bottom:8px}
.post-card h3{font-size:19px;margin-bottom:8px;line-height:1.3}
.post-card h3 a{color:var(--text)}
.post-card h3 a:hover{color:var(--primary)}
.post-card p{color:var(--muted);font-size:14px;margin-bottom:14px;flex:1}
.post-card .meta{display:flex;justify-content:space-between;font-size:12.5px;color:var(--muted);align-items:center}

.post-list{display:grid;grid-template-columns:repeat(2,1fr);gap:24px}
.post-single{background:var(--card);border:1px solid var(--border);border-radius:var(--radius);overflow:hidden;box-shadow:var(--shadow)}
.post-single .feature-img{aspect-ratio:21/9;background:var(--grad)}
.post-single .feature-img img{width:100%;height:100%;object-fit:cover}
.post-single .body{padding:34px}
.post-single h1{font-size:clamp(26px,4vw,38px);margin:8px 0 14px}
.post-single .meta{color:var(--muted);font-size:13px;margin-bottom:24px;display:flex;gap:14px;flex-wrap:wrap}
.post-single .post-content{font-size:17px;line-height:1.85;color:var(--text)}
.post-single .post-content h2{font-size:26px;margin:30px 0 12px}
.post-single .post-content h3{font-size:21px;margin:24px 0 10px}
.post-single .post-content p{margin-bottom:16px}
.post-single .post-content ul,.post-single .post-content ol{margin:0 0 16px 1.2rem}
.post-single .post-content li{margin-bottom:6px}
.post-single .post-content blockquote{border-left:4px solid var(--primary);padding:10px 20px;margin:18px 0;background:rgba(37,99,235,.04);border-radius:8px;color:var(--muted)}
.post-single .post-content img{border-radius:12px;margin:14px 0}
.post-single .post-content a{color:var(--primary);text-decoration:underline}
.post-labels{display:flex;gap:8px;flex-wrap:wrap;margin:28px 0;padding-top:20px;border-top:1px solid var(--border)}
.post-labels a{background:rgba(37,99,235,.08);color:var(--primary);padding:5px 12px;border-radius:20px;font-size:13px;font-weight:600}
.author-box{display:flex;gap:16px;align-items:center;padding:20px;background:rgba(37,99,235,.04);border-radius:var(--radius);margin-top:24px}
.author-box .av{width:60px;height:60px;border-radius:50%;background:var(--grad);color:#fff;display:grid;place-items:center;font-weight:800;font-size:22px;font-family:'Plus Jakarta Sans'}
.author-box b{display:block;font-size:16px}
.author-box span{color:var(--muted);font-size:13.5px}

/* Static page */
.page-body{background:var(--card);border:1px solid var(--border);border-radius:var(--radius);padding:40px;box-shadow:var(--shadow)}
.page-body h1{font-size:34px;margin-bottom:8px}
.page-body .updated{color:var(--muted);font-size:13px;margin-bottom:26px}
.page-body h2{font-size:24px;margin:30px 0 12px}
.page-body h3{font-size:19px;margin:22px 0 8px}
.page-body p{margin-bottom:14px;color:var(--text)}
.page-body ul,.page-body ol{margin:0 0 14px 1.2rem}
.page-body li{margin-bottom:6px}
.page-body a{color:var(--primary);text-decoration:underline}

/* ===== SIDEBAR ===== */
.sidebar{display:flex;flex-direction:column;gap:22px;position:sticky;top:84px}
.widget{background:var(--card);border:1px solid var(--border);border-radius:var(--radius);padding:22px}
.widget h3,.widget .title{font-size:16px;margin-bottom:16px;padding-bottom:12px;border-bottom:2px solid var(--border);font-weight:700}
.widget ul{list-style:none;padding:0;margin:0}
.widget li{padding:9px 0;border-bottom:1px solid var(--border);font-size:14px}
.widget li:last-child{border-bottom:none}
.widget a{color:var(--text)}
.widget a:hover{color:var(--primary)}
.search-box{display:flex;gap:8px}
.search-box input{flex:1;padding:11px 14px;border:1.5px solid var(--border);border-radius:10px;background:var(--bg);color:var(--text);font-family:inherit;font-size:14px}
[data-theme="dark"] .search-box input{background:#0B1220}
.search-box button{background:var(--grad);color:#fff;border:none;padding:0 18px;border-radius:10px;cursor:pointer;font-weight:600}
.pop-post{display:flex;gap:12px;padding:11px 0;border-bottom:1px solid var(--border)}
.pop-post:last-child{border-bottom:none}
.pop-post .pp-thumb{width:64px;height:64px;border-radius:10px;background:var(--grad);flex-shrink:0;overflow:hidden}
.pop-post .pp-thumb img{width:100%;height:100%;object-fit:cover}
.pop-post .pp-body h4{font-size:14px;font-weight:600;line-height:1.35;margin-bottom:4px;font-family:Inter}
.pop-post .pp-body h4 a{color:var(--text)}
.pop-post .pp-body span{font-size:12px;color:var(--muted)}
.social-links{display:flex;gap:10px;flex-wrap:wrap}
.social-links a{width:40px;height:40px;border-radius:10px;background:rgba(37,99,235,.08);color:var(--primary);display:grid;place-items:center;font-size:16px;font-weight:700}
.social-links a:hover{background:var(--grad);color:#fff;transform:translateY(-2px)}

/* ===== ADS ===== */
.ad-zone{background:rgba(37,99,235,.03);border:1px dashed var(--border);border-radius:var(--radius);padding:18px;text-align:center;color:var(--muted);font-size:13px;margin:18px 0;min-height:90px;display:grid;place-items:center}
.ad-zone::before{content:"Advertisement";display:block;font-size:10px;letter-spacing:.1em;text-transform:uppercase;opacity:.6;margin-bottom:4px}
.ad-zone[data-empty="false"]::before{display:none}
.ad-zone[data-empty="false"]{background:transparent;border:none;padding:0;min-height:auto}
.header-ad{margin:0 auto;max-width:var(--maxw);padding:8px 20px}
.home-ad{margin:30px auto;max-width:970px;padding:0 20px}

/* ===== FOOTER ===== */
.site-footer{background:var(--secondary);color:#CBD5E1;padding:60px 0 0;margin-top:60px}
[data-theme="dark"] .site-footer{background:#070C18}
.footer-grid{display:grid;grid-template-columns:1.6fr 1fr 1fr 1.2fr;gap:36px;padding-bottom:40px}
.footer-brand .brand{color:#fff;margin-bottom:14px}
.footer-brand p{font-size:14px;color:#94A3B8;margin-bottom:18px;max-width:300px}
.footer-col h4{color:#fff;font-size:15px;margin-bottom:18px;text-transform:uppercase;letter-spacing:.06em;font-family:Inter}
.footer-col ul{list-style:none;padding:0}
.footer-col li{margin-bottom:10px}
.footer-col a{color:#94A3B8;font-size:14px}
.footer-col a:hover{color:#fff}
.footer-contact .item{display:flex;gap:10px;margin-bottom:12px;font-size:14px;color:#94A3B8}
.footer-bottom{border-top:1px solid rgba(255,255,255,.08);padding:22px 0;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:14px;font-size:13px;color:#94A3B8}
.footer-bottom a{color:#CBD5E1}

/* PWA install button */
#installAppBtn{display:none}
#installAppBtn.show{display:inline-flex}

/* Pagination */
.blog-pager{display:flex;justify-content:center;gap:10px;margin:40px 0 0;flex-wrap:wrap}
.blog-pager a,.blog-pager span{padding:10px 18px;border-radius:10px;background:var(--card);border:1px solid var(--border);font-weight:600;font-size:14px;color:var(--text)}
.blog-pager a:hover{border-color:var(--primary);color:var(--primary)}
#blog-pager .selected{background:var(--grad);color:#fff;border-color:transparent}

/* Toast */
.toast{position:fixed;bottom:24px;left:50%;transform:translateX(-50%) translateY(120%);background:var(--secondary);color:#fff;padding:14px 24px;border-radius:12px;font-weight:600;font-size:14px;z-index:9999;box-shadow:var(--shadow-lg);transition:transform .3s ease}
[data-theme="dark"] .toast{background:#1E293B}
.toast.show{transform:translateX(-50%) translateY(0)}

/* Responsive */
@media (max-width:980px){
  .hero-grid,.tool-layout{grid-template-columns:1fr}
  .grid-4{grid-template-columns:repeat(2,1fr)}
  .layout{grid-template-columns:1fr}
  .sidebar{position:static}
  .preview-wrap{position:static}
  .footer-grid{grid-template-columns:1fr 1fr}
  .hero-card{order:-1;max-width:480px}
}
@media (max-width:760px){
  .nav-menu{display:none}
  .menu-toggle{display:grid}
  .grid-3,.grid-2{grid-template-columns:1fr}
  .post-list{grid-template-columns:1fr}
  .field-row{grid-template-columns:1fr}
  .hero{padding:50px 0 40px}
  .section{padding:50px 0}
  .doc{padding:24px}
  .doc .doc-head{flex-direction:column;gap:14px}
  .doc .parties{grid-template-columns:1fr}
  .cta{padding:40px 24px}
  .page-body,.post-single .body{padding:24px}
  .footer-grid{grid-template-columns:1fr;gap:28px}
  .tool-actions .btn{flex:1 1 100%}
}
@media print{
  .site-header,.site-footer,.sidebar,.preview-toolbar,.nav,.ad-zone,.cta,.tool-form,#installAppBtn,.menu-toggle,.crumbs,.adsterra-zone,.footer-ad{display:none !important}
  body{background:#fff}
  .preview-wrap{position:static !important}
  .doc{box-shadow:none;border:none;max-width:100%;margin:0;padding:0}
  .tool-page,.container{padding:0;max-width:100%}
  .tool-layout{display:block}
}

body.script:
//
  (function(){
    'use strict';

    /* ---------- Theme toggle ---------- */
    var root=document.documentElement;
    var saved=localStorage.getItem('ip-theme');
    if(saved){root.setAttribute('data-theme',saved);}
    else if(window.matchMedia&&window.matchMedia('(prefers-color-scheme:dark)').matches){root.setAttribute('data-theme','dark');}
    var tt=document.getElementById('themeToggle');
    if(tt){
      tt.addEventListener('click',function(){
        var cur=root.getAttribute('data-theme')==='dark'?'light':'dark';
        root.setAttribute('data-theme',cur);
        localStorage.setItem('ip-theme',cur);
      });
    }

    /* ---------- Mobile nav ---------- */
    var mt=document.getElementById('menuToggle'),nm=document.getElementById('navMobile');
    if(mt&&nm){
      mt.addEventListener('click',function(){document.body.classList.toggle('nav-open');});
      nm.querySelectorAll('a').forEach(function(a){a.addEventListener('click',function(){document.body.classList.remove('nav-open');});});
    }

    /* ---------- Toast ---------- */
    var toastEl=document.getElementById('toast'),toastT;
    window.ipToast=function(msg){
      if(!toastEl)return;
      toastEl.textContent=msg;toastEl.classList.add('show');
      clearTimeout(toastT);toastT=setTimeout(function(){toastEl.classList.remove('show');},2600);
    };

    /* ---------- FAQ ---------- */
    document.querySelectorAll('.faq-q').forEach(function(q){
      q.addEventListener('click',function(){
        var item=q.parentNode,a=q.nextElementSibling,open=item.classList.contains('open');
        document.querySelectorAll('.faq-item').forEach(function(i){i.classList.remove('open');i.querySelector('.faq-a').style.maxHeight=null;});
        if(!open){item.classList.add('open');a.style.maxHeight=a.scrollHeight+'px';}
      });
    });

    /* ---------- Utilities ---------- */
    function money(n,cur){
      var v=parseFloat(n||0);
      if(isNaN(v))v=0;
      return (cur||'$')+v.toLocaleString(undefined,{minimumFractionDigits:2,maximumFractionDigits:2});
    }
    function esc(s){return String(s==null?'':s).replace(/[&<>"']/g,function(c){return{'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c];});}
    function el(id){return document.getElementById(id);}
    function fmtDate(v){
      if(!v)return '';
      var d=new Date(v);
      if(isNaN(d))return v;
      return d.toLocaleDateString(undefined,{year:'numeric',month:'short',day:'numeric'});
    }

    /* ---------- INVOICE GENERATOR ---------- */
    var invForm=el('invItems');
    if(invForm){
      var cur=el('invCurrency');
      function invRows(){
        return Array.prototype.slice.call(document.querySelectorAll('#invItemsBody tr'));
      }
      function invRecalc(){
        var rows=invRows(),sub=0;
        rows.forEach(function(r){
          var q=parseFloat(r.querySelector('.i-qty').value)||0;
          var p=parseFloat(r.querySelector('.i-price').value)||0;
          var line=q*p;r.querySelector('.i-total').textContent=money(line,cur.value);sub+=line;
        });
        var taxP=parseFloat(el('invTax').value)||0,discP=parseFloat(el('invDisc').value)||0;
        var disc=sub*discP/100,tax=(sub-disc)*taxP/100,total=sub-disc+tax;
        var c=cur.value;
        document.querySelector('.inv-subtotal').textContent=money(sub,c);
        document.querySelector('.inv-tax').textContent=money(tax,c);
        document.querySelector('.inv-disc').textContent='-'+money(disc,c);
        document.querySelector('.inv-total').textContent=money(total,c);
        invRender();
      }
      function invRender(){
        var c=cur.value;
        el('pBrand').innerHTML=esc(el('invCoName').value)+'';
        el('pCoName').textContent=el('invCoName').value;
        el('pCoAddr').textContent=el('invCoAddr').value;
        el('pInvNo').textContent=el('invNo').value;
        el('pDue').textContent=fmtDate(el('invDue').value);
        el('pClient').textContent=el('invClient').value;
        el('pClientAddr').textContent=el('invClientAddr').value;
        var body=el('pItems');body.innerHTML='';
        var sub=0;
        invRows().forEach(function(r){
          var d=r.querySelector('.i-desc').value||'';
          var q=parseFloat(r.querySelector('.i-qty').value)||0;
          var p=parseFloat(r.querySelector('.i-price').value)||0;
          var line=q*p;sub+=line;
          if(!d&&!q&&!p)return;
          var tr=document.createElement('tr');
          tr.innerHTML='<td>'+esc(d)+'</td><td>'+q+'</td><td>'+money(p,c)+'</td><td>'+money(line,c)+'</td>';
          body.appendChild(tr);
        });
        var taxP=parseFloat(el('invTax').value)||0,discP=parseFloat(el('invDisc').value)||0;
        var disc=sub*discP/100,tax=(sub-disc)*taxP/100,total=sub-disc+tax;
        var ht='';
        ht+='<div class="trow"><span>Subtotal</span><b>'+money(sub,c)+'</b></div>';
        if(disc>0)ht+='<div class="trow"><span>Discount ('+discP+'%)</span><b>-'+money(disc,c)+'</b></div>';
        if(tax>0)ht+='<div class="trow"><span>Tax ('+taxP+'%)</span><b>'+money(tax,c)+'</b></div>';
        ht+='<div class="grand"><span>Total Due</span><span class="amt">'+money(total,c)+'</span></div>';
        el('pTotals').innerHTML=ht;
      }
      el('invItemsBody').addEventListener('input',invRecalc);
      el('invItemsBody').addEventListener('click',function(e){
        if(e.target.classList.contains('del-row')){
          if(invRows().length>1){e.target.closest('tr').remove();invRecalc();}
        }
      });
      el('invAddItem').addEventListener('click',function(){
        var tr=document.createElement('tr');
        tr.innerHTML='<td><input class="i-desc" type="text" placeholder="Item description"/></td><td class="col-qty"><input class="i-qty" type="number" value="1"/></td><td class="col-price"><input class="i-price" type="number" value="0"/></td><td class="i-total">0</td><td><button class="del-row" type="button">&#215;</button></td>';
        el('invItemsBody').appendChild(tr);invRecalc();
      });
      ['invCoName','invCoAddr','invClient','invClientAddr','invNo','invDue','invTax','invDisc','invCurrency'].forEach(function(id){
        var e=el(id);if(e)e.addEventListener('input',invRecalc);
      });
      el('invPrint').addEventListener('click',function(){window.print();});
      el('invShare').addEventListener('click',function(){
        var data={t:'inv',co:el('invCoName').value,addr:el('invCoAddr').value,cl:el('invClient').value,cla:el('invClientAddr').value,no:el('invNo').value,due:el('invDue').value,c:cur.value,tax:el('invTax').value,disc:el('invDisc').value,items:invRows().map(function(r){return[r.querySelector('.i-desc').value,r.querySelector('.i-qty').value,r.querySelector('.i-price').value];})};
        try{
          var u=location.origin+location.pathname+'#d='+btoa(unescape(encodeURIComponent(JSON.stringify(data))));
          if(navigator.share){navigator.share({title:'Invoice '+data.no,url:u}).catch(function(){});}
          else{navigator.clipboard.writeText(u).then(function(){ipToast('Share link copied!');},function(){prompt('Copy this link:',u);});}
        }catch(err){ipToast('Sharing not supported');}
      });
      el('invPdf').addEventListener('click',function(){ipPrintPDF('Invoice_'+(el('invNo').value||'document'),'invPreview');});
      invRecalc();
    }

    /* ---------- RECEIPT GENERATOR ---------- */
    var rcPreview=el('rcPreview');
    if(rcPreview){
      var rcur=el('rcCurrency');
      function rcRecalc(){
        var c=rcur.value;
        el('rpCoName').textContent=el('rcCoName').value;
        el('rpCoAddr').textContent=el('rcCoAddr').value;
        el('rpNo').textContent=el('rcNo').value;
        el('rpDate').textContent=fmtDate(el('rcDate').value);
        el('rpFrom').textContent=el('rcFrom').value;
        el('rpFor').textContent=el('rcFor').value;
        el('rpMethod').textContent=el('rcMethod').value;
        el('rpTxn').textContent=el('rcTxn').value||'\u2014';
        var st=el('rcStatus').value;
        el('rpStatus').textContent=st.charAt(0).toUpperCase()+st.slice(1);
        var pill=el('rpStatusPill');
        pill.className='status-pill '+st;pill.textContent=st.toUpperCase();
        var amt=parseFloat(el('rcAmount').value)||0;
        el('rpAmount').textContent=money(amt,c);
        el('rpTotal').textContent=money(amt,c);
      }
      ['rcCoName','rcCoAddr','rcNo','rcDate','rcFrom','rcFor','rcAmount','rcMethod','rcStatus','rcTxn','rcCurrency'].forEach(function(id){
        var e=el(id);if(e)e.addEventListener('input',rcRecalc);
      });
      el('rcPrint').addEventListener('click',function(){window.print();});
      el('rcPdf').addEventListener('click',function(){ipPrintPDF('Receipt_'+(el('rcNo').value||'document'),'rcPreview');});
      rcRecalc();
    }

    /* ---------- PDF via print (print-to-PDF) ---------- */
    function ipPrintPDF(name,srcId){
      var src=el(srcId);if(!src)return;
      var w=window.open('','_blank','width=820,height=1000');
      if(!w){ipToast('Allow pop-ups to export PDF');return;}
      var css='*{box-sizing:border-box}body{font-family:Inter,Arial,sans-serif;color:#1E293B;margin:0;padding:40px}.doc{background:#fff;padding:0}.doc-head{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:3px solid #2563EB;padding-bottom:22px;margin-bottom:26px}.doc-brand{font-family:Plus Jakarta Sans,Arial,sans-serif;font-weight:800;font-size:26px}.doc-brand span{color:#2563EB}.doc-type{font-size:32px;font-weight:800;color:#2563EB;font-family:Plus Jakarta Sans,Arial,sans-serif}.doc-meta{text-align:right;color:#64748B;font-size:13px;line-height:1.7}.doc-meta b{color:#1E293B}.parties{display:grid;grid-template-columns:1fr 1fr;gap:20px;margin-bottom:24px}.party .lbl{font-size:11px;text-transform:uppercase;letter-spacing:.08em;color:#94A3B8;font-weight:700;margin-bottom:4px}.party .nm{font-weight:700;font-size:16px;margin-bottom:3px}.party .det{font-size:13px;color:#64748B;line-height:1.6;white-space:pre-line}table.doc-items{width:100%;border-collapse:collapse;margin:14px 0}table.doc-items th{background:#1E293B;color:#fff;text-align:left;padding:12px 14px;font-size:12px;text-transform:uppercase}table.doc-items th:last-child,table.doc-items td:last-child{text-align:right}table.doc-items td{padding:12px 14px;border-bottom:1px solid #E2E8F0;font-size:14px}.doc-totals{margin-left:auto;width:280px;margin-top:18px}.doc-totals .trow{display:flex;justify-content:space-between;padding:7px 0;font-size:14px;color:#64748B}.doc-totals .trow b{color:#1E293B}.doc-totals .grand{border-top:2px solid #1E293B;margin-top:6px;padding-top:12px;font-size:20px;font-weight:800;color:#1E293B;font-family:Plus Jakarta Sans,Arial,sans-serif}.doc-totals .grand .amt{color:#2563EB}.doc-foot{margin-top:36px;padding-top:20px;border-top:1px solid #E2E8F0;font-size:12px;color:#94A3B8;text-align:center}.status-pill{display:inline-block;padding:4px 12px;border-radius:20px;font-size:11px;font-weight:700;text-transform:uppercase}.status-pill.paid{background:#DCFCE7;color:#166534}.status-pill.unpaid{background:#FEE2E2;color:#991B1B}.status-pill.partial{background:#FEF3C7;color:#92400E}';
      w.document.write('<!doctype html><html><head><meta charset="utf-8"><title>'+esc(name)+'</title><style>'+css+'</style></head><body>'+src.outerHTML+'</body></html>');
      w.document.close();w.focus();
      setTimeout(function(){w.print();},350);
    }

    /* ---------- Contact form ---------- */
    var cf=el('contactForm');
    if(cf){cf.addEventListener('submit',function(e){e.preventDefault();cf.reset();ipToast('Thanks! Your message has been recorded.');});}

    /* ---------- Set today's date in date inputs ---------- */
    var today=new Date().toISOString().split('T')[0];
    ['invDue','rcDate'].forEach(function(id){var e=el(id);if(e&&!e.value)e.value=today;});
    if(el('invDue')&&invForm)invRecalc&&invRecalc();
    if(el('rcDate')&&rcPreview)rcRecalc&&rcRecalc();

    /* ---------- PWA: Service Worker ---------- */
    if('serviceWorker' in navigator){
      window.addEventListener('load',function(){
        navigator.serviceWorker.register('/sw.js').catch(function(){});
      });
    }

    /* ---------- PWA: Install prompt ---------- */
    var deferredPrompt,installBtn=el('installAppBtn');
    window.addEventListener('beforeinstallprompt',function(e){
      e.preventDefault();deferredPrompt=e;
      if(installBtn)installBtn.classList.add('show');
    });
    if(installBtn){
      installBtn.addEventListener('click',function(){
        if(!deferredPrompt){ipToast('Install from your browser menu');return;}
        deferredPrompt.prompt();
        deferredPrompt.userChoice.then(function(){deferredPrompt=null;installBtn.classList.remove('show');});
      });
    }
    window.addEventListener('appinstalled',function(){if(installBtn)installBtn.classList.remove('show');});

    /* ---------- AD SETTINGS PANEL ---------- */
    var AD_SLOTS=[
      {id:'header',name:'Header Banner',sel:'#adsterra-header'},
      {id:'home-banner',name:'Homepage Banner',sel:'#adsterra-home-banner'},
      {id:'sidebar',name:'Sidebar Banner',sel:'#adsterra-sidebar'},
      {id:'inarticle',name:'In-Article Ad',sel:'#adsterra-inarticle'},
      {id:'footer',name:'Footer Banner',sel:'#adsterra-footer'},
      {id:'native',name:'Native Ad Area',sel:'#adsterra-native'},
      {id:'socialbar',name:'Social Bar',sel:'#adsterra-socialbar'}
    ];
    var panel=el('adSettingsPanel'),back=el('adSettingsBackdrop'),openB=el('adSettingsOpen'),closeB=el('adSettingsClose'),fields=el('adFields');
    function openPanel(){panel.style.transform='translateX(0)';panel.setAttribute('aria-hidden','false');back.style.opacity='1';back.style.pointerEvents='auto';}
    function closePanel(){panel.style.transform='translateX(100%)';panel.setAttribute('aria-hidden','true');back.style.opacity='0';back.style.pointerEvents='none';}
    if(openB)openB.addEventListener('click',openPanel);
    if(closeB)closeB.addEventListener('click',closePanel);
    if(back)back.addEventListener('click',closePanel);
    function buildAdFields(){
      var store=getAdStore();fields.innerHTML='';
      AD_SLOTS.forEach(function(s){
        var wrap=document.createElement('div');wrap.style.cssText='margin-bottom:14px';
        var lbl=document.createElement('label');lbl.textContent=s.name;lbl.style.cssText='display:block;font-weight:600;font-size:13px;margin-bottom:5px';
        var ta=document.createElement('textarea');ta.rows=3;ta.dataset.slot=s.id;ta.placeholder='Paste '+s.name+' Adsterra code...';
        ta.style.cssText='width:100%;padding:10px;border:1.5px solid var(--border);border-radius:10px;background:var(--bg);color:var(--text);font-family:JetBrains Mono,monospace;font-size:12px';
        ta.value=store[s.id]||'';wrap.appendChild(lbl);wrap.appendChild(ta);fields.appendChild(wrap);
      });
    }
    function getAdStore(){try{return JSON.parse(localStorage.getItem('ip-ads')||'{}');}catch(e){return{};}}
    function applyAds(){
      var store=getAdStore();
      AD_SLOTS.forEach(function(s){
        var nodes=document.querySelectorAll('.adsterra-zone[data-slot="'+s.id+'"]');
        nodes.forEach(function(node){
          var code=(store[s.id]||'').trim();
          if(code){node.innerHTML=code;node.setAttribute('data-empty','false');node.style.display='';}
          else{node.setAttribute('data-empty','true');}
        });
      });
    }
    if(el('adSave'))el('adSave').addEventListener('click',function(){
      var store={};fields.querySelectorAll('textarea').forEach(function(ta){if(ta.value.trim())store[ta.dataset.slot]=ta.value.trim();});
      localStorage.setItem('ip-ads',JSON.stringify(store));applyAds();closePanel();ipToast('Ad settings saved');
    });
    if(el('adClear'))el('adClear').addEventListener('click',function(){
      localStorage.removeItem('ip-ads');buildAdFields();applyAds();ipToast('Ad settings cleared');
    });
    buildAdFields();applyAds();

    /* ---------- Lazy load images ---------- */
    if('loading' in HTMLImageElement.prototype){}else{
      var io=new IntersectionObserver(function(es){es.forEach(function(e){if(e.isIntersecting){var im=e.target;im.src=im.dataset.src;io.unobserve(im);}});});
      document.querySelectorAll('img[data-src]').forEach(function(im){io.observe(im);});
    }
  })();
  //
